sql:
SELECT * 
FROM surveys 
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'Country_Name_Here');

external_knowledge:
; Country rank is based on public support for climate change legislation; 
; 'last_survey_date' is used to break ties in country ranks, with more recent dates being ranked higher; 
; The 10th highest-ranked country is considered.

